from __future__ import annotations

from dataclasses import MISSING, asdict, dataclass, field, fields
from datetime import datetime, timezone
from typing import Any, Dict, List, Optional


def utc_now() -> str:
    return datetime.now(timezone.utc).isoformat()


@dataclass
class Block:
    id: str
    kind: str
    text: str
    page_number: int
    bbox: Optional[List[float]] = None
    confidence: Optional[float] = None
    metadata: Dict[str, Any] = field(default_factory=dict)


@dataclass
class Page:
    id: str
    number: int
    text: str = ""
    image_path: Optional[str] = None
    blocks: List[Block] = field(default_factory=list)
    metadata: Dict[str, Any] = field(default_factory=dict)


@dataclass
class Document:
    id: str
    source_path: str
    title: str
    created_at: str = field(default_factory=utc_now)
    pages: List[Page] = field(default_factory=list)
    metadata: Dict[str, Any] = field(default_factory=dict)

    def to_dict(self) -> Dict[str, Any]:
        return asdict(self)

    @classmethod
    def from_dict(cls, data: Dict[str, Any]) -> "Document":
        pages = []
        for page_data in data.get("pages", []):
            blocks = [Block(**block) for block in page_data.get("blocks", [])]
            page = Page(
                id=page_data["id"],
                number=page_data["number"],
                text=page_data.get("text", ""),
                image_path=page_data.get("image_path"),
                blocks=blocks,
                metadata=page_data.get("metadata", {}),
            )
            pages.append(page)
        return cls(
            id=data["id"],
            source_path=data["source_path"],
            title=data["title"],
            created_at=data.get("created_at", utc_now()),
            pages=pages,
            metadata=data.get("metadata", {}),
        )


@dataclass
class DocumentProfile:
    document_id: str
    title: str
    source_type: str
    page_count: int
    text_page_count: int
    image_page_count: int
    total_words: int
    page_types: Dict[str, int]
    headings: List[str] = field(default_factory=list)
    topics: List[str] = field(default_factory=list)
    entities: List[str] = field(default_factory=list)
    extraction_confidence: Dict[str, Any] = field(default_factory=dict)
    structured_reference_inventory: Dict[str, List[str]] = field(default_factory=dict)
    created_at: str = field(default_factory=utc_now)

    def to_dict(self) -> Dict[str, Any]:
        return asdict(self)

    @classmethod
    def from_dict(cls, data: Dict[str, Any]) -> "DocumentProfile":
        kwargs: Dict[str, Any] = {}
        for f in fields(cls):
            if f.name in data:
                val = data[f.name]
                if f.name == "structured_reference_inventory":
                    kwargs[f.name] = {
                        str(k): list(v) if isinstance(v, (list, tuple)) else []
                        for k, v in (val or {}).items()
                    }
                elif f.name in ("headings", "topics", "entities"):
                    kwargs[f.name] = list(val) if val is not None else []
                elif f.name == "page_types":
                    kwargs[f.name] = dict(val) if val is not None else {}
                elif f.name == "extraction_confidence":
                    kwargs[f.name] = dict(val) if val is not None else {}
                else:
                    kwargs[f.name] = val
            elif f.default_factory is not MISSING:
                kwargs[f.name] = f.default_factory()
            elif f.default is not MISSING:
                kwargs[f.name] = f.default
            else:
                raise KeyError(f"Missing required field {f.name!r} in document profile payload")
        return cls(**kwargs)


@dataclass
class Chunk:
    id: str
