from __future__ import annotations

import re
from collections import Counter, defaultdict
from typing import Dict, List

from retrieval_research.schema import Chunk, Evidence


TOKEN_RE = re.compile(r"[a-z0-9_]+")
ENTITY_RE = re.compile(r"\b(?:[A-Z][A-Za-z0-9&.-]*|[A-Z]{2,})(?:\s+(?:[A-Z][A-Za-z0-9&.-]*|[A-Z]{2,})){0,3}\b")
ACRONYM_DEF_RE = re.compile(
    r"\b([A-Z][A-Za-z0-9&.-]+(?:\s+[A-Z][A-Za-z0-9&.-]+){1,6})\s*\(([A-Z][A-Z0-9-]{1,12})\)"
)
REVERSED_ACRONYM_DEF_RE = re.compile(
    r"\b([A-Z][A-Z0-9-]{1,12})\s*\(([A-Z][A-Za-z0-9&.-]+(?:\s+[A-Z][A-Za-z0-9&.-]+){1,6})\)"
)
QUOTED_ENTITY_RE = re.compile(r"[\"'`]([A-Za-z][A-Za-z0-9&./_-]+(?:\s+[A-Za-z0-9&./_-]+){1,5})[\"'`]")
SECTION_REF_RE = re.compile(r"\b(?:section|chapter|appendix)\s+([A-Z0-9][A-Za-z0-9 ._-]{0,60})", re.IGNORECASE)
NUMBERED_REF_RE = re.compile(
    r"\b(figure|fig\.|table|page|eq\.|equation)s?\s*([A-Z]?\d+(?:\.\d+)*(?:\s*(?:-|to|and|,)\s*[A-Z]?\d+(?:\.\d+)*)*)",
    re.IGNORECASE,
)
CITATION_REF_RE = re.compile(r"\[(\d{1,3})\]")
DOI_RE = re.compile(r"\b10\.\d{4,9}/[-._;()/:A-Z0-9]+\b", re.IGNORECASE)
ARXIV_RE = re.compile(r"\barXiv:\s*([0-9]{4}\.[0-9]{4,5}(?:v\d+)?)\b", re.IGNORECASE)
URL_RE = re.compile(r"\bhttps?://[^\s)>\]]+")
NUMERIC_VALUE_RE = re.compile(r"[A-Z]?\d+(?:\.\d+)*")
NUMERIC_RANGE_RE = re.compile(
    r"([A-Z]?\d+(?:\.\d+)?)\s*[-–—to]+\s*([A-Z]?\d+(?:\.\d+)?)",
    re.IGNORECASE,
)

ENTITY_STOPWORDS = {
    "A",
    "An",
    "And",
    "For",
    "In",
    "No",
    "The",
    "This",
    "To",
}


OCR_REFERENCE_NORMALIZATIONS = (
    (r"\bsectlon\b", "section"),
    (r"\bsectlon[s]?\b", "section"),
    (r"\bsec(?:tlon|tion)\b", "section"),
    (r"\bsect1on\b", "section"),
    (r"\bsect10n\b", "section"),
    (r"\bsectiion\b", "section"),
    (r"\bsectl0n\b", "section"),
    (r"\bsecti0n\b", "section"),
    (r"\bsectton\b", "section"),
    (r"\bsecton\b", "section"),
    (r"\bsec ion\b", "section"),
    (r"\bsec tlon\b", "section"),
    (r"\bchapler\b", "chapter"),
    (r"\bchapte r\b", "chapter"),
    (r"\bchaoter\b", "chapter"),
    (r"\bchapt3r\b", "chapter"),
    (r"\bchapt er\b", "chapter"),
    (r"\bchap ter\b", "chapter"),
    (r"\bappendlx\b", "appendix"),
    (r"\bappenclix\b", "appendix"),
    (r"\bappendix\b", "appendix"),
    (r"\bapp3ndix\b", "appendix"),
    (r"\bappen dix\b", "appendix"),
    (r"\bappendixx\b", "appendix"),
    (r"\bfig(?:ures?)?\b", "figure"),
    (r"\bf1g(?:ures?)?\b", "figure"),
    (r"\bflg(?:ures?)?\b", "figure"),
    (r"\bfi(?:g|q)ures?\b", "figure"),
    (r"\bfigu res?\b", "figure"),
    (r"\bfig re\b", "figure"),
    (r"\bftgures?\b", "figure"),
    (r"\bligures?\b", "figure"),
    (r"\btab1es?\b", "table"),
    (r"\btabie\b", "table"),
    (r"\btabl es?\b", "table"),
    (r"\btab les?\b", "table"),
    (r"\btabke\b", "table"),
    (r"\btahle\b", "table"),
    (r"\bequat1on\b", "equation"),
    (r"\bequatlons?\b", "equation"),
    (r"\bequat10n\b", "equation"),
    (r"\bequati0n\b", "equation"),
    (r"\bequation\b", "equation"),
    (r"\beq uation\b", "equation"),
    (r"\beqnation\b", "equation"),
    (r"\bequ ation\b", "equation"),
    (r"\barx1v\b", "arXiv"),
    (r"\barxlv\b", "arXiv"),
    (r"\barXiv\b", "arXiv"),
    (r"\barxi v\b", "arXiv"),
)


def _normalize_ocr_reference_text(text: str) -> str:
    normalized = text
    for pattern, replacement in OCR_REFERENCE_NORMALIZATIONS:
        normalized = re.sub(pattern, replacement, normalized, flags=re.IGNORECASE)
    return normalized


def _tokens(text: str) -> set[str]:
    return set(TOKEN_RE.findall(text.lower()))


def _clean_entity(value: str) -> str | None:
    cleaned = " ".join(value.strip(" \t\n\r.,;:()[]{}").split())
    if len(cleaned) < 3 or cleaned in ENTITY_STOPWORDS:
        return None
    if cleaned.lower() in {word.lower() for word in ENTITY_STOPWORDS}:
        return None
    return cleaned


def _entities(text: str) -> set[str]:
    entities = set()
    for match in ENTITY_RE.finditer(text):
        value = _clean_entity(match.group(0))
        if not value:
            continue
        entities.add(value)
        parts = value.split()
        for start in range(len(parts)):
            for end in range(start + 1, min(len(parts), start + 3) + 1):
                sub_value = " ".join(parts[start:end])
                if len(sub_value) >= 3 and sub_value not in ENTITY_STOPWORDS:
                    entities.add(sub_value)
    for pattern in (ACRONYM_DEF_RE, REVERSED_ACRONYM_DEF_RE):
        for full_name, acronym in pattern.findall(text):
            for value in (full_name, acronym):
                cleaned = _clean_entity(value)
                if cleaned:
                    entities.add(cleaned)
    for value in QUOTED_ENTITY_RE.findall(text):
        cleaned = _clean_entity(value)
        if cleaned:
            entities.add(cleaned)
    return entities


def _number_values(value: str) -> set[str]:
    values = {match.group(0).lower() for match in NUMERIC_VALUE_RE.finditer(value)}
    for match in NUMERIC_RANGE_RE.finditer(value):
        a_raw, b_raw = match.group(1), match.group(2)
        prefix = re.sub(r"\d+", "", a_raw).lower()
        a_digits = re.search(r"\d+", a_raw)
        b_digits = re.search(r"\d+", b_raw)
        if a_digits and b_digits:
            try:
                a, b = int(a_digits.group()), int(b_digits.group())
                for i in range(a + 1, b):
                    values.add(f"{prefix}{i}".lower())
            except ValueError:
                pass
    return values


def _section_aliases(section: str | None) -> set[str]:
    key = _section_key(section)
    if not key:
        return set()
    aliases = {key}
    match = re.match(r"^([a-z]?\d+(?:\.\d+)*)(?:\s+(.+))?$", key)
    if match:
        num_part = match.group(1)
        aliases.add(num_part)
        parts = num_part.split(".")
        for i in range(1, len(parts)):
            aliases.add(".".join(parts[:i]))
        if match.group(2):
            aliases.add(match.group(2).strip())
    return {alias for alias in aliases if alias}


def _references(text: str) -> set[str]:
    text = _normalize_ocr_reference_text(text)
    refs = set()
    for kind, numbers in NUMBERED_REF_RE.findall(text):
        normalized_kind = "figure" if kind.lower() == "fig." else kind.lower()
        normalized_kind = "equation" if normalized_kind == "eq." else normalized_kind
        for number in _number_values(numbers):
            refs.add(f"{normalized_kind}:{number}")
    for value in CITATION_REF_RE.findall(text):
        refs.add(f"citation:{value}")
